from collections import deque
from typing import List


class Solution:
    def countShortestPaths(self, n: int, guards: List[List[int]]) -> List[int]:
        # 起点在底行正中，终点在顶行正中（题面坐标：行 x，列 y，左下为 (0,0)）
        sx, sy = 0, n // 2
        ex, ey = n - 1, n // 2
        # ban[x][y] 为 True 表示该格落在某个哨兵的九宫格内，不可站立
        ban = [[False] * n for _ in range(n)]
        for g in guards:
            gx, gy = int(g[0]), int(g[1])
            for dx in (-1, 0, 1):
                for dy in (-1, 0, 1):
                    nx, ny = gx + dx, gy + dy
                    if 0 <= nx < n and 0 <= ny < n:
                        ban[nx][ny] = True
        # 起终点若已在禁区内，直接无解
        if ban[sx][sy] or ban[ex][ey]:
            return [0, 0]
        dist = [[-1] * n for _ in range(n)]
        ways = [[0] * n for _ in range(n)]
        dist[sx][sy] = 0
        ways[sx][sy] = 1
        q = deque([(sx, sy)])
        dirs = ((1, 0), (-1, 0), (0, 1), (0, -1))
        while q:
            x, y = q.popleft()
            for dx, dy in dirs:
                nx, ny = x + dx, y + dy
                if nx < 0 or nx >= n or ny < 0 or ny >= n or ban[nx][ny]:
                    continue
                nd = dist[x][y] + 1
                if dist[nx][ny] == -1:
                    # 第一次到达 (nx,ny)，最短路长度确定
                    dist[nx][ny] = nd
                    ways[nx][ny] = ways[x][y]
                    q.append((nx, ny))
                elif dist[nx][ny] == nd:
                    # 另一条同样长度的最短路汇入
                    ways[nx][ny] += ways[x][y]
        if dist[ex][ey] == -1:
            return [0, 0]
        # 第二维：顶点数 = 边数 + 1
        return [ways[ex][ey], dist[ex][ey] + 1]
