import java.util.ArrayDeque;
import java.util.ArrayList;
import java.util.Deque;
import java.util.List;

class Solution {
    public List<Integer> countShortestPaths(int n, List<List<Integer>> guards) {
        int sy = n / 2;
        int sx = 0, ex = n - 1, ey = sy;
        boolean[][] ban = new boolean[n][n];
        // 将每个哨兵的 3x3 禁区并入 ban
        for (List<Integer> g : guards) {
            int gx = g.get(0), gy = g.get(1);
            for (int dx = -1; dx <= 1; dx++) {
                for (int dy = -1; dy <= 1; dy++) {
                    int nx = gx + dx, ny = gy + dy;
                    if (nx >= 0 && nx < n && ny >= 0 && ny < n) {
                        ban[nx][ny] = true;
                    }
                }
            }
        }
        if (ban[sx][sy] || ban[ex][ey]) {
            return make(0, 0);
        }
        int[][] dist = new int[n][n];
        long[][] ways = new long[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                dist[i][j] = -1;
            }
        }
        int[][] dirs = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
        dist[sx][sy] = 0;
        ways[sx][sy] = 1;
        Deque<int[]> q = new ArrayDeque<>();
        q.add(new int[] {sx, sy});
        while (!q.isEmpty()) {
            int[] cur = q.pollFirst();
            int x = cur[0], y = cur[1];
            for (int[] d : dirs) {
                int nx = x + d[0], ny = y + d[1];
                if (nx < 0 || nx >= n || ny < 0 || ny >= n || ban[nx][ny]) {
                    continue;
                }
                int nd = dist[x][y] + 1;
                if (dist[nx][ny] == -1) {
                    dist[nx][ny] = nd;
                    ways[nx][ny] = ways[x][y];
                    q.addLast(new int[] {nx, ny});
                } else if (dist[nx][ny] == nd) {
                    // 同一最短路层上的多条前驱，累加方案数
                    ways[nx][ny] += ways[x][y];
                }
            }
        }
        if (dist[ex][ey] == -1) {
            return make(0, 0);
        }
        return make((int) ways[ex][ey], dist[ex][ey] + 1);
    }

    private static List<Integer> make(int a, int b) {
        List<Integer> r = new ArrayList<>();
        r.add(a);
        r.add(b);
        return r;
    }
}
