#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> countShortestPaths(int n, vector<vector<int>>& guards) {
        // 题面坐标：左下为 (0,0)，入口底行正中，司令部顶行正中
        int sy = n / 2;
        int sx = 0, ex = n - 1, ey = sy;
        // ban[x][y]=1 表示该格落在某个哨兵的九宫格（切比雪夫距离<=1）内，不可走
        vector<vector<char>> ban(n, vector<char>(n, 0));
        for (auto& g : guards) {
            int gx = g[0], gy = g[1];
            for (int dx = -1; dx <= 1; dx++) {
                for (int dy = -1; dy <= 1; dy++) {
                    int nx = gx + dx, ny = gy + dy;
                    if (nx >= 0 && nx < n && ny >= 0 && ny < n) {
                        ban[nx][ny] = 1;
                    }
                }
            }
        }
        // 起点或终点已在禁区内，无法出发或无法到达
        if (ban[sx][sy] || ban[ex][ey]) {
            return {0, 0};
        }
        const int dirs[4][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};  // 上、下、左、右四邻
        vector<vector<int>> dist(n, vector<int>(n, -1));             // -1 表示未访问
        vector<vector<long long>> ways(n, vector<long long>(n, 0));   // 最短路条数，可能较大用 long long
        deque<pair<int, int>> q;
        dist[sx][sy] = 0;
        ways[sx][sy] = 1;  // 起点方案数为 1
        q.push_back({sx, sy});
        while (!q.empty()) {
            int x = q.front().first, y = q.front().second;
            q.pop_front();
            for (int k = 0; k < 4; k++) {
                int nx = x + dirs[k][0], ny = y + dirs[k][1];
                if (nx < 0 || nx >= n || ny < 0 || ny >= n || ban[nx][ny]) {
                    continue;
                }
                int nd = dist[x][y] + 1;  // 走到邻居的边数 = 当前最短路 +1
                if (dist[nx][ny] == -1) {
                    // 首次到达：最短路长度确定，方案数继承自前驱
                    dist[nx][ny] = nd;
                    ways[nx][ny] = ways[x][y];
                    q.push_back({nx, ny});
                } else if (dist[nx][ny] == nd) {
                    // 同一最短路层上另有前驱指向 (nx,ny)，累加方案数
                    ways[nx][ny] += ways[x][y];
                }
            }
        }
        if (dist[ex][ey] == -1) {
            return {0, 0};
        }
        // 返回值：条数；路径「长度」为题面规定的顶点数 = 边数 + 1
        return {(int)ways[ex][ey], dist[ex][ey] + 1};
    }
};
