```c
#include <stdlib.h>
#include <string.h>

/**
 * @param n 敌军阵营的边长
 * @param guards 哨兵位置数组
 * @param guardsSize 哨兵数量
 * @param guardsColSize 每个哨兵坐标子数组的长度（恒为2）
 * @param returnSize 返回数组长度（恒为2）
 * @return [最短路径条数, 最短路径长度]
 */
int* countShortestPaths(int n, int** guards, int guardsSize, int* guardsColSize, int* returnSize) {
    *returnSize = 2;
    int* result = (int*)malloc(2 * sizeof(int));
    result[0] = 0;
    result[1] = 0;

    // 起点：底行正中 (0, n/2)；终点：顶行正中 (n-1, n/2)
    int sy = n / 2;
    int sx = 0, ex = n - 1, ey = sy;

    // 标记每个哨兵的 3×3 九宫格（切比雪夫距离 ≤ 1）为禁区
    char** ban = (char**)malloc(n * sizeof(char*));
    for (int i = 0; i < n; i++) {
        ban[i] = (char*)calloc(n, sizeof(char));
    }
    for (int i = 0; i < guardsSize; i++) {
        int gx = guards[i][0], gy = guards[i][1];
        for (int dx = -1; dx <= 1; dx++) {
            for (int dy = -1; dy <= 1; dy++) {
                int nx = gx + dx, ny = gy + dy;
                if (nx >= 0 && nx < n && ny >= 0 && ny < n) {
                    ban[nx][ny] = 1;
                }
            }
        }
    }

    // 起点或终点在禁区内则不可达
    if (ban[sx][sy] || ban[ex][ey]) {
        for (int i = 0; i < n; i++) free(ban[i]);
        free(ban);
        return result;
    }

    // BFS：dist 存最短边数（-1 表示未访问），ways 存方案数
    int** dist = (int**)malloc(n * sizeof(int*));
    long long** ways = (long long**)malloc(n * sizeof(long long*));
    for (int i = 0; i < n; i++) {
        dist[i] = (int*)malloc(n * sizeof(int));
        ways[i] = (long long*)malloc(n * sizeof(long long));
        for (int j = 0; j < n; j++) {
            dist[i][j] = -1;
            ways[i][j] = 0;
        }
    }

    int dirs[4][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};  // 上下左右
    dist[sx][sy] = 0;
    ways[sx][sy] = 1;

    // 数组模拟队列
    int** q = (int**)malloc(n * n * sizeof(int*));
    int head = 0, tail = 0;
    q[tail] = (int*)malloc(2 * sizeof(int));
    q[tail][0] = sx; q[tail][1] = sy;
    tail++;

    while (head < tail) {
        int x = q[head][0], y = q[head][1];
        free(q[head]);
        head++;
        for (int k = 0; k < 4; k++) {
            int nx = x + dirs[k][0], ny = y + dirs[k][1];
            if (nx < 0 || nx >= n || ny < 0 || ny >= n || ban[nx][ny]) continue;
            int nd = dist[x][y] + 1;
            if (dist[nx][ny] == -1) {
                // 首次到达：最短路长度确定，方案数继承自前驱
                dist[nx][ny] = nd;
                ways[nx][ny] = ways[x][y];
                q[tail] = (int*)malloc(2 * sizeof(int));
                q[tail][0] = nx; q[tail][1] = ny;
                tail++;
            } else if (dist[nx][ny] == nd) {
                // 同一最短路层上另有前驱，累加方案数
                ways[nx][ny] += ways[x][y];
            }
        }
    }

    // 可达时填写结果：条数 + 顶点数（边数 + 1）
    if (dist[ex][ey] != -1) {
        result[0] = (int)ways[ex][ey];
        result[1] = dist[ex][ey] + 1;
    }

    // 释放内存
    for (int i = 0; i < n; i++) {
        free(ban[i]);
        free(dist[i]);
        free(ways[i]);
    }
    free(ban);
    free(dist);
    free(ways);
    free(q);

    return result;
}
